import { useState, useRef } from "react";
import "./DocumentUpload.css";

const DOC_TYPES = ["Cheque", "Invoice", "KYC Document", "Loan Agreement", "Bank Statement"];

const PIPELINE_STEPS = [
  { id: "ocr",       label: "AWS Textract OCR",     sub: "Field extraction",        icon: "◈" },
  { id: "layout",    label: "LayoutLM v3",           sub: "Spatial understanding",   icon: "⊞" },
  { id: "ner",       label: "BERT Financial NER",    sub: "Entity recognition",      icon: "◑" },
  { id: "sig",       label: "Siamese Sig Verify",    sub: "Signature authentication", icon: "◎" },
  { id: "fraud",     label: "XGBoost Fraud Score",   sub: "Risk probability",        icon: "◉" },
  { id: "shap",      label: "SHAP Explainability",   sub: "Decision reasoning",      icon: "≋" },
];

function ProcessingModal({ file, onClose }) {
  const [step, setStep] = useState(0);
  const [done, setDone] = useState(false);
  const [result, setResult] = useState(null);

  useState(() => {
    let s = 0;
    const id = setInterval(() => {
      s++;
      setStep(s);
      if (s >= PIPELINE_STEPS.length) {
        clearInterval(id);
        setDone(true);
        setResult({
          fields: {
            "Payee Name": "Vikram Enterprises Pvt Ltd",
            "Account No.": "HDFC0042190••••",
            "IFSC Code": "HDFC0001241",
            "Amount (₹)": "2,40,000",
            "Date": "05 Apr 2026",
            "Cheque No.": "012941",
          },
          fraudScore: 14,
          sigConfidence: 91,
          decision: "APPROVED",
        });
      }
    }, 900);
    return () => clearInterval(id);
  });

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="processing-modal" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <span className="card-title">Processing Pipeline</span>
          <button className="btn btn-ghost btn-sm" onClick={onClose}>✕</button>
        </div>

        <div className="modal-file-info">
          <span className="mono" style={{ color: "var(--accent-cyan)" }}>
            {file?.name || "CHQ-sample-hdfc.pdf"}
          </span>
          <span className="badge badge-cyan">Cheque</span>
        </div>

        {/* Pipeline steps */}
        <div className="pipeline-steps">
          {PIPELINE_STEPS.map((s, i) => {
            const state = i < step ? "done" : i === step ? "active" : "pending";
            return (
              <div key={s.id} className={`pipeline-step ${state}`}>
                <div className="step-indicator">
                  {state === "done" ? "✓" : state === "active" ? "⟳" : s.icon}
                </div>
                <div className="step-body">
                  <span className="step-label">{s.label}</span>
                  <span className="step-sub">{s.sub}</span>
                </div>
                {state === "active" && (
                  <div className="step-spinner" />
                )}
              </div>
            );
          })}
        </div>

        {/* Result */}
        {done && result && (
          <div className="modal-result animate-in">
            <div className="result-header">
              <span className="card-title">Extracted Fields</span>
              <span className={`badge ${result.decision === "APPROVED" ? "badge-green" : "badge-red"}`}>
                {result.decision}
              </span>
            </div>
            <div className="extracted-fields">
              {Object.entries(result.fields).map(([k, v]) => (
                <div key={k} className="field-row">
                  <span className="field-key">{k}</span>
                  <span className="field-val mono">{v}</span>
                </div>
              ))}
            </div>
            <div className="result-scores">
              <div className="score-item">
                <span className="score-key">Fraud Risk</span>
                <span className="mono" style={{ color: "var(--accent-green)" }}>{result.fraudScore}%</span>
              </div>
              <div className="score-item">
                <span className="score-key">Sig. Confidence</span>
                <span className="mono" style={{ color: "var(--accent-cyan)" }}>{result.sigConfidence}%</span>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default function DocumentUpload() {
  const [dragging, setDragging] = useState(false);
  const [files, setFiles] = useState([]);
  const [processing, setProcessing] = useState(null);
  const [docType, setDocType] = useState("Cheque");
  const fileRef = useRef();

  const handleDrop = e => {
    e.preventDefault();
    setDragging(false);
    const dropped = Array.from(e.dataTransfer.files);
    addFiles(dropped);
  };

  const addFiles = newFiles => {
    const mapped = newFiles.map(f => ({
      id: Date.now() + Math.random(),
      file: f,
      name: f.name,
      size: (f.size / 1024).toFixed(1) + " KB",
      status: "queued",
      type: docType,
    }));
    setFiles(prev => [...prev, ...mapped]);
  };

  const handleProcess = (item) => {
    setProcessing(item);
  };

  const removeFile = (id) => {
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  return (
    <div className="upload-page">
      {processing && (
        <ProcessingModal file={processing.file} onClose={() => setProcessing(null)} />
      )}

      <div className="upload-layout">
        {/* Left: Drop zone + config */}
        <div className="upload-left">
          {/* Doc type selector */}
          <div className="card animate-in">
            <div className="card-header" style={{ marginBottom: 16 }}>
              <span className="card-title">Document Configuration</span>
            </div>
            <div className="form-group">
              <label className="form-label">Document Type</label>
              <div className="doc-type-grid">
                {DOC_TYPES.map(t => (
                  <button
                    key={t}
                    className={`doc-type-btn ${docType === t ? "active" : ""}`}
                    onClick={() => setDocType(t)}
                  >
                    {t}
                  </button>
                ))}
              </div>
            </div>

            <div className="form-group">
              <label className="form-label">Processing Priority</label>
              <select className="input" defaultValue="normal">
                <option value="low">Low — batch overnight</option>
                <option value="normal">Normal — within 5 min</option>
                <option value="high">High — under 30s</option>
                <option value="realtime">Realtime — &lt; 200ms</option>
              </select>
            </div>

            <div className="form-group">
              <label className="form-label">Client / Bank Reference</label>
              <input className="input" placeholder="e.g. HDFC-MUM-BRANCH-041" />
            </div>

            <div className="toggle-row">
              <div>
                <div className="toggle-label">Enable SHAP Explanations</div>
                <div className="toggle-sub">Generates RBI-compliant decision reasons</div>
              </div>
              <div className="toggle toggle-on" />
            </div>

            <div className="toggle-row">
              <div>
                <div className="toggle-label">Signature Verification</div>
                <div className="toggle-sub">Requires reference signature on file</div>
              </div>
              <div className="toggle toggle-on" />
            </div>
          </div>
        </div>

        {/* Right: Drop zone + queue */}
        <div className="upload-right">
          {/* Drop zone */}
          <div
            className={`drop-zone animate-in animate-in-delay-1 ${dragging ? "dragging" : ""}`}
            onDragOver={e => { e.preventDefault(); setDragging(true); }}
            onDragLeave={() => setDragging(false)}
            onDrop={handleDrop}
            onClick={() => fileRef.current.click()}
          >
            <input
              ref={fileRef}
              type="file"
              multiple
              accept=".pdf,.png,.jpg,.jpeg,.tiff"
              style={{ display: "none" }}
              onChange={e => addFiles(Array.from(e.target.files))}
            />
            <div className="drop-icon">⊕</div>
            <div className="drop-title">Drop documents here</div>
            <div className="drop-sub">PDF, PNG, JPG, TIFF — up to 25MB per file</div>
            <div className="drop-formats">
              {["Cheque", "Invoice", "KYC", "Loan", "Statement"].map(f => (
                <span key={f} className="tag" style={{ background: "var(--bg-elevated)", color: "var(--text-tertiary)", border: "1px solid var(--border-default)" }}>
                  {f}
                </span>
              ))}
            </div>
            {dragging && <div className="drop-scan-line" />}
          </div>

          {/* Queue */}
          {files.length > 0 && (
            <div className="card upload-queue animate-in">
              <div className="card-header">
                <span className="card-title">Upload Queue</span>
                <div style={{ display: "flex", gap: 8 }}>
                  <span className="badge badge-cyan">{files.length} files</span>
                  <button className="btn btn-primary btn-sm"
                    onClick={() => setFiles(prev => prev.map(f => ({ ...f, status: "queued" })))}>
                    Process All
                  </button>
                </div>
              </div>

              <div className="queue-list">
                {files.map(item => (
                  <div key={item.id} className="queue-item">
                    <div className="queue-file-icon">
                      {item.name.endsWith(".pdf") ? "⊟" : "⊞"}
                    </div>
                    <div className="queue-info">
                      <span className="queue-name">{item.name}</span>
                      <div className="queue-meta">
                        <span className="mono" style={{ color: "var(--text-tertiary)", fontSize: 11 }}>{item.size}</span>
                        <span className="badge badge-cyan" style={{ fontSize: 10, padding: "1px 6px" }}>{item.type}</span>
                      </div>
                    </div>
                    <div className="queue-actions">
                      <button className="btn btn-primary btn-sm" onClick={() => handleProcess(item)}>
                        Run
                      </button>
                      <button className="btn btn-ghost btn-sm" onClick={() => removeFile(item.id)}>
                        ✕
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Supported OCR engines */}
          <div className="card engine-card animate-in animate-in-delay-2">
            <div className="card-header" style={{ marginBottom: 12 }}>
              <span className="card-title">Active ML Pipeline</span>
              <span className="badge badge-green">Operational</span>
            </div>
            <div className="engine-list">
              {[
                { name: "AWS Textract",     role: "Primary OCR",         ping: "18ms", ok: true },
                { name: "LayoutLM v3",      role: "Field Extraction",    ping: "42ms", ok: true },
                { name: "BERT-FIN NER",     role: "Entity Recognition",  ping: "31ms", ok: true },
                { name: "XGBoost Scorer",   role: "Fraud Risk",          ping: "9ms",  ok: true },
                { name: "Siamese Net",      role: "Signature Verify",    ping: "55ms", ok: true },
              ].map(e => (
                <div key={e.name} className="engine-row">
                  <div className={`engine-status ${e.ok ? "ok" : "err"}`} />
                  <div className="engine-info">
                    <span className="engine-name">{e.name}</span>
                    <span className="engine-role">{e.role}</span>
                  </div>
                  <span className="mono engine-ping">{e.ping}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
